    int a[n+1];
    for (int i = 1; i <= n; i++) cin >> a[i];
    sort(a+1, a+n+1);
    for (int i = 2; i <= n - 1; i+=2) {
        if (a[i] != a[i+1]) {
            cout << "NO\n";
            return;
        }
    }
    cout << "YES\n";
}

